/**
 * soundService.js — Ring tone using an <audio> element + base64 WAV.
 *
 * WHY WE DROPPED WEB AUDIO API:
 *   AudioContext requires a user gesture before it can play sound.
 *   The ring is triggered by a WebSocket event (no user gesture), so
 *   AudioContext stays suspended and plays nothing — even with the
 *   "unlock on first tap" workaround, the gesture and the ring happen
 *   in different event loops and mobile browsers still block it.
 *
 * THIS APPROACH:
 *   A plain <audio> element with a looping base64-encoded WAV.
 *   Browsers allow <audio>.play() from socket events as long as the
 *   user has interacted with the page at least once beforehand
 *   (which they have — they logged in, tapped around, etc.).
 *   This is the same technique used by food-delivery apps (Zomato,
 *   Swiggy) for new-order alerts.
 */

const WAV_B64 = '';

let audio = null;
let ringing = false;

function getAudio() {
  if (!audio) {
    audio = new Audio('data:audio/wav;base64,' + WAV_B64);
    audio.loop = true;
    audio.volume = 1.0;
    audio.preload = 'auto';
  }
  return audio;
}

export function startRing() {
  if (ringing) return;
  ringing = true;
  const a = getAudio();
  a.currentTime = 0;
  const p = a.play();
  if (p && typeof p.catch === 'function') {
    p.catch(err => {
      // Autoplay blocked — browser requires a user gesture.
      // This should not happen in normal use (user has already tapped the app).
      console.warn('[soundService] play() blocked:', err.message);
    });
  }
}

export function stopRing() {
  ringing = false;
  if (audio) {
    audio.pause();
    audio.currentTime = 0;
  }
}

export function isRinging() {
  return ringing;
}

// unlockAudio is kept for compatibility but is no longer needed.
export function unlockAudio() {}