/**
 * pushService.js — Firebase Cloud Messaging (FCM) push notifications.
 *
 * HOW IT WORKS:
 *  1. On Android, after the rider logs in, call initPushNotifications(uid).
 *  2. Capacitor registers the device with FCM and gives us a token.
 *  3. We save that token to the backend (PUT /riders/:id/fcm-token).
 *  4. When a new order arrives and the app is CLOSED, the backend sends
 *     an FCM push → Android wakes the device and shows a notification.
 *  5. When the rider taps the notification, the app opens to the order page.
 *
 * Uses dynamic imports so the browser/Vite never complains about missing
 * Capacitor packages — they are only loaded at runtime on a real device.
 * Install when ready: npm install @capacitor/core @capacitor/push-notifications @capacitor/local-notifications
 */

import { ridersAPI } from './api';
import { logger } from '../utils/logger';

const log = logger('Push');

let initialized = false;

/** Returns true only when running inside a Capacitor native app (Android/iOS) */
function isNative() {
  try {
    return typeof window !== 'undefined' && window.Capacitor?.isNativePlatform?.();
  } catch {
    return false;
  }
}

/**
 * Call once after login on Android.
 * @param {string}   riderUid   - The logged-in rider's UID
 * @param {function} onNavigate - Called with orderId when rider taps a push
 */
export async function initPushNotifications(riderUid, onNavigate) {
  if (!isNative()) return;   // no-op in the browser
  if (initialized) return;
  initialized = true;

  try {
    // Dynamic imports — only resolved on the device, never by Vite in the browser
    const { PushNotifications }  = await import('@capacitor/push-notifications');
    const { LocalNotifications } = await import('@capacitor/local-notifications');
    const { Capacitor }          = await import('@capacitor/core');

    // 1. Create notification channel (Android 8+ requirement)
    if (Capacitor.getPlatform() === 'android') {
      await LocalNotifications.createChannel({
        id:          'order_alerts',
        name:        'Order Alerts',
        description: 'Notifications for new delivery orders',
        importance:  5,
        vibration:   true,
        sound:       'default',
        visibility:  1,
      });
    }

    // 2. Request permission
    const permission = await PushNotifications.requestPermissions();
    if (permission.receive !== 'granted') {
      log.warn('Push permission denied by rider');
      return;
    }

    // 3. Register with FCM
    await PushNotifications.register();

    // 4. Get FCM token and save to backend
    PushNotifications.addListener('registration', async (token) => {
      log.info('FCM token received');
      try {
        await ridersAPI.saveFcmToken(riderUid, token.value);
        log.info('FCM token saved to backend');
      } catch (err) {
        log.warn('Failed to save FCM token', { error: err.message });
      }
    });

    // 5. App OPEN — socket handles ORDER_AVAILABLE already, nothing to do
    PushNotifications.addListener('pushNotificationReceived', () => {});

    // 6. App CLOSED/BACKGROUND — rider taps notification → open order page
    PushNotifications.addListener('pushNotificationActionPerformed', (action) => {
      const data = action.notification.data;
      if (data?.type === 'ORDER_AVAILABLE' && data?.orderId) {
        setTimeout(() => onNavigate?.(data.orderId), 500);
      }
    });

    // 7. Registration error
    PushNotifications.addListener('registrationError', (err) => {
      log.warn('FCM registration error', { error: err.error });
    });

    log.info('Push notifications initialized');
  } catch (err) {
    log.warn('initPushNotifications failed (non-fatal)', { error: err.message });
  }
}

/**
 * Call on logout — removes FCM token from backend so the rider
 * doesn't receive pushes after they log out.
 */
export async function clearPushToken(riderUid) {
  if (!isNative()) return;
  try {
    await ridersAPI.clearFcmToken(riderUid);
    initialized = false;
    log.info('FCM token cleared on logout');
  } catch (err) {
    log.warn('Failed to clear FCM token', { error: err.message });
  }
}